      .execute()

    await queueService.add('audit-event', {
      entityType: 'item',
      entityId: itemId,
      action: 'created',
    })

    return { itemId, name: data.name, slug: data.slug, priceCents: data.priceCents, stock: data.stock }
  },
})

getItem:
export const getItem = pikkuSessionlessFunc({
  expose: true,
  description: 'Get a single item by ID.',
  input: GetItemInput,
  output: GetItemOutput,
  func: async ({ kysely }, { itemId }) => {
    const row = await kysely
      .selectFrom('item')
      .innerJoin('category', 'category.categoryId', 'item.categoryId')
      .select([
        'item.itemId', 'item.name', 'item.slug', 'item.description',
        'item.priceCents', 'item.stock', 'item.imageUrl', 'item.isActive',
        'item.createdAt', 'item.updatedAt',
        'category.categoryId', 'category.name as categoryName', 'category.slug as categorySlug',
      ])
      .where('item.itemId', '=', itemId)
      .executeTakeFirst()

    if (!row) throw new Error(`Item not found: ${itemId}`)

    return {
      ...row,
      category: { categoryId: row.categoryId, name: row.categoryName, slug: row.categorySlug },
    }
  },
})

listItems:
export const listItems = pikkuSessionlessFunc({
  expose: true,
  description: 'List items, optionally filtered by category or search query.',
  input: ListItemsInput,
  output: ListItemsOutput,
  func: async ({ kysely }, { categorySlug, search, limit, offset }) => {
    let query = kysely
      .selectFrom('item')
      .innerJoin('category', 'category.categoryId', 'item.categoryId')
      .select([
        'item.itemId', 'item.name', 'item.slug', 'item.description',
        'item.priceCents', 'item.stock', 'item.imageUrl',
        'category.categoryId', 'category.name as categoryName', 'category.slug as categorySlug',
      ])
      .where('item.isActive', '=', 1)

    if (categorySlug) {
      query = query.where('category.slug', '=', categorySlug)
    }
    if (search) {
      query = query.where((eb) =>
        eb.or([
          eb('item.name', 'like', `%${search}%`),
          eb('item.description', 'like', `%${search}%`),
        ])
      )
    }

    const [rows, countRow] = await Promise.all([
      query.limit(limit).offset(offset).execute(),
      query.select((eb) => eb.fn.countAll<number>().as('count')).executeTakeFirst(),
    ])

    return {
      items: rows.map((r) => ({
        itemId: r.itemId,
        name: r.name,
        slug: r.slug,
        description: r.description,
        priceCents: r.priceCents,
        stock: r.stock,
        imageUrl: r.imageUrl,
        category: { categoryId: r.categoryId, name: r.categoryName, slug: r.categorySlug },
      })),
      total: Number(countRow?.count ?? 0),
    }
  },
})

updateItem:
export const updateItem = pikkuFunc({
  expose: true,
  description: 'Update an item. Admin only.',
  input: UpdateItemInput,
  func: async ({ kysely }, { itemId, ...patch }) => {
    const updates: Record<string, unknown> = {
      updatedAt: new Date().toISOString(),
    }
    if (patch.name !== undefined) updates.name = patch.name
    if (patch.description !== undefined) updates.description = patch.description
    if (patch.priceCents !== undefined) updates.priceCents = patch.priceCents
    if (patch.stock !== undefined) updates.stock = patch.stock
    if (patch.imageUrl !== undefined) updates.imageUrl = patch.imageUrl
    if (patch.isActive !== undefined) updates.isActive = patch.isActive ? 1 : 0

    await kysely.updateTable('item').set(updates).where('itemId', '=', itemId).execute()
  },
})

