cleanupAbandonedBaskets:
export const cleanupAbandonedBaskets = pikkuSessionlessFunc({
  expose: false,
  description: 'Cron job: remove anonymous baskets older than 7 days.',
  func: async ({ kysely, logger }) => {
    const cutoff = new Date()
    cutoff.setDate(cutoff.getDate() - 7)

    const result = await kysely
      .deleteFrom('basket')
      .where('userId', 'is', null)
      .where('updatedAt', '<', cutoff.toISOString())
      .executeTakeFirst()

    logger.info({ event: 'cleanup_abandoned_baskets', deleted: Number(result.numDeletedRows ?? 0) })
  },
})

authConfig:
const configFactory: AuthConfigOrFactory = async (services) => {
  const { kysely, secrets } = services as any
  const secret = (await secrets.getSecret('AUTH_SECRET').catch(() => null)) ?? DEV_AUTH_SECRET

  return {
    providers: [
      Credentials({
        credentials: {
          email: { label: 'Email', type: 'email' },
          password: { label: 'Password', type: 'password' },
        },
        async authorize(credentials) {
          const email = (credentials?.email as string | undefined)?.toLowerCase()
          const password = credentials?.password as string | undefined
          if (!email || !password) return null

          const user = await kysely
            .selectFrom('appUser')
            .where('email', '=', email)
            .select(['userId', 'role', 'name', 'email', 'passwordHash'])
            .executeTakeFirst()

          if (!user || !user.passwordHash) return null
          const ok = await verifyPassword(password, user.passwordHash)
          if (!ok) return null

          return { id: user.userId, email: user.email, name: user.name, role: user.role }
        },
      }),
    ],
    callbacks: {
      jwt({ token, user }: any) {
        if (user) { token.role = user.role; token.userId = user.id }
        return token
      },
      session({ session, token }: any) {
        if (token) { session.role = token.role; session.userId = token.userId }
        return session
      },
    },
    session: { strategy: 'jwt' as const },
    secret,
    trustHost: true,
    basePath: '/auth',
  }
}

checkoutWorkflow:
export const checkoutWorkflow = defineWorkflow({
  name: 'checkout',
  input: CheckoutInput,
  output: CheckoutOutput,
  steps: [
    {
      name: 'validate-basket',
      func: pikkuSessionlessFunc({
        func: async ({ kysely }, { basketId }) => {
          const items = await kysely
            .selectFrom('basketItem')
            .innerJoin('item', 'item.itemId', 'basketItem.itemId')
            .select(['basketItem.itemId', 'basketItem.quantity', 'item.stock', 'item.name', 'item.priceCents'])
            .where('basketItem.basketId', '=', basketId)
            .execute()

          if (items.length === 0) throw new Error('Basket is empty')
          for (const i of items) {
            if (i.quantity > i.stock) throw new Error(`Insufficient stock for "${i.name}"`)
          }

          const totalCents = items.reduce((s, i) => s + i.priceCents * i.quantity, 0)
          return { items, totalCents }
        },
      }),
    },
    {
      name: 'create-order',
      func: pikkuSessionlessFunc({
        func: async ({ kysely }, { basketId, userId, shippingAddress }, ctx) => {
          const { items, totalCents } = ctx.steps['validate-basket']
          const orderId = randomUUID()
          const now = new Date().toISOString()

          await kysely.insertInto('order').values({
            orderId, userId, status: 'pending', totalCents,
            shippingAddress: JSON.stringify(shippingAddress),
            createdAt: now, updatedAt: now,
          }).execute()

          await kysely.insertInto('orderItem').values(
            items.map((i: any) => ({
              orderItemId: randomUUID(), orderId,
              itemId: i.itemId, quantity: i.quantity, unitPriceCents: i.priceCents,
            }))
          ).execute()

          return { orderId, totalCents }
        },
      }),
    },
    {
      name: 'process-payment',
      func: pikkuSessionlessFunc({
        func: async ({ paymentService, kysely }, { cardToken }, ctx) => {
          const { orderId, totalCents } = ctx.steps['create-order']
          const result = await paymentService.charge({ amountCents: totalCents, cardToken, orderId })

          await kysely.insertInto('payment').values({
            paymentId: randomUUID(), orderId, amountCents: totalCents,
            provider: 'fake', status: result.status,
            providerRef: result.status === 'succeeded' ? result.providerRef : null,
            createdAt: new Date().toISOString(),
          }).execute()

          return result
        },
      }),
    },
    {
      name: 'finalize',
      func: pikkuSessionlessFunc({
        func: async ({ kysely, queueService }, { basketId, userId }, ctx) => {
          const { orderId, totalCents } = ctx.steps['create-order']
          const payment = ctx.steps['process-payment']
          const now = new Date().toISOString()
          const status = payment.status === 'succeeded' ? 'paid' : 'payment_failed'

          await kysely.updateTable('order').set({ status, updatedAt: now }).where('orderId', '=', orderId).execute()

          if (status === 'paid') {
            await kysely.deleteFrom('basketItem').where('basketId', '=', basketId).execute()
            await queueService.add('send-order-confirmation', { orderId, userId })
          }

          return { orderId, status, totalCents }
        },
      }),
    },
  ],
})

